def sanitize_filename(filename):
    # illegal_chars = r'[<>:"/\\|?*\x00-\x1F]'
    illegal_chars = r'[<>:"/\\|?*]'
    return re.sub(illegal_chars, '', filename)

# 毫秒转换
def convert_milliseconds(ms):
    minutes = ms // 60000
    ms = ms % 60000
    seconds = ms // 1000
    milliseconds = ms % 1000
    return f"{minutes}:{seconds:02}:{milliseconds:03}"

