# bpm检查输入是否是数字或小数点
def validate_input(new_value):
    if new_value == "" or re.fullmatch(r'\d*\.?\d*', new_value):
        return True
    else:
        return False

# 检查两位整数
def validate_input2(new_value):
    if new_value == "" or re.fullmatch(r'\d{0,2}', new_value):
        return True
    else:
        return False

# 检查三位整数（音量）
def validate_input3(new_value):
    if new_value == "" or re.fullmatch(r'\d{0,3}', new_value):
        return True
    else:
        return False

# 一位数字（1-9）
def validate_input4(new_value):
    if new_value == "" or re.fullmatch(r'^[1-9]$', new_value):
        return True
    else:
        return False

def validate_input5(P):
    if P == "": return True
    if re.fullmatch(r"^-?\d{0,4}$", P):
        if P == "-": return True
        return -9999 <= int(P) <= 9999
    
    return False

