def on_circle_click(event):
    global select
    tags = panel.gettags('current')
    for tag in tags:
        if tag.startswith('note_'):
            circle_index = int(tag.split('_')[1])
            if circle_index in select:
                panel.itemconfig(f'note_{circle_index}', outline='black')
                select.remove(circle_index)
                # print(f"取消选中了第 {circle_index} 个圆")
                update_textbox()
            else:
                panel.itemconfig(f'note_{circle_index}', outline='yellow')
                select.add(circle_index)
                # print(f"选中了第 {circle_index} 个圆")
                update_textbox()

