# 插线清除
def fuck_clear():
    global New_HitObjects, New_TimingPoints_Red, New_TimingPoints_Green # 好像没啥用，先留着吧（
    start = start_time.get()
    end = end_time.get()  
    mode = line_value.current()
    try:
        if file_select.get() == '':
            raise Exception(didnt_choose_file)

        if not os.path.isfile(file_select.get()):
            raise Exception(file_not_exist)

        if start == '' or end == '':
            raise Exception(time_not_full)

        if re.match(r'^[0-9]+:[0-9]{2}:[0-9]{3}\s', start):
            start_convert = int(start.split(':')[0]) * 60000 + int(start.split(':')[1]) * 1000 + int(start.split(':')[2][0:3])
        elif re.match(r'^[0-9]+$', start):
            start_convert = int(start)
        else:
            raise Exception(stime_not_correct)

        if re.match(r'^[0-9]+:[0-9]{2}:[0-9]{3}\s', end):
            end_convert = int(end.split(':')[0]) * 60000 + int(end.split(':')[1]) * 1000 + int(end.split(':')[2][0:3])
        elif re.match(r'^[0-9]+$', end):
            end_convert = int(end)
        else:
            raise Exception(etime_not_correct)

        if start_convert > end_convert:
            raise Exception(stime_etime)
        
        if start_convert == end_convert:
            raise Exception(stime_etime_equal)
        
        if mode == 5: # 绿线
            cleared_Green = []
            for line in TimingPoint_Green:
                line_split = line.split(',')
                if int(line_split[0]) >= start_convert and int(line_split[0]) <= end_convert:
                    continue
                cleared_Green.append(line)

            clear_combine_timing = sorted(TimingPoint_Red + cleared_Green, key=lambda x: int(x.split(',')[0]))

        elif mode == 6: # 红线
            cleared_Red = []
            for line in TimingPoint_Red:
                line_split = line.split(',')
                if int(line_split[0]) >= start_convert and int(line_split[0]) <= end_convert:
                    continue
                cleared_Red.append(line)

            clear_combine_timing = sorted(cleared_Red + TimingPoint_Green, key=lambda x: int(x.split(',')[0]))

        elif mode == 7: # 全删
            cleared_Timing = []
            for line in TimingPoints:
                line_split = line.split(',')
                if int(line_split[0]) >= start_convert and int(line_split[0]) <= end_convert:
                    continue
                cleared_Timing.append(line)

            clear_combine_timing = sorted(cleared_Timing, key=lambda x: int(x.split(',')[0]))

        diff_name = f'{filename_info["Artist"]} - {filename_info["Title"]} ({filename_info["Creator"]}) [{filename_info["Version"]}].osu'
        diff_name_convert = f'{filename_info["Artist"]} - {filename_info["Title"]} ({filename_info["Creator"]}) [{filename_info["Version"]} (NB Convert)].osu'
        if ori.get() == 1:
            filename = f'{os.path.dirname(file_select.get())}/' + sanitize_filename(diff_name)
            New_Info = Info
        else:
            filename = f'{os.path.dirname(file_select.get())}/' + sanitize_filename(diff_name_convert)
            New_Info = []
            for line in Info:
                if line[0:8] == 'Version:':
                    New_Info.append(line[0:-1] + ' (NB Convert)\n')
                    continue
                New_Info.append(line)

        with open(filename, 'w', encoding='utf-8') as f:
            for line in New_Info:
                f.write(line)
            f.write('\n')
            f.write('[TimingPoints]\n')
            for line in clear_combine_timing:
                f.write(line)
            f.write('\n')
            f.write('[HitObjects]\n')
            for line in HitObjects:
                f.write(line)
            f.close()
        
        log_add_msg(delete_line)
        init(if_all=True)
        read_file()
    except Exception as e:
        log_add_msg(e)
        # traceback.print_exc()

