# 流速统一  
def adjust():
    global TimingPoints, TimingPoint_Green, TimingPoint_Red, New_TimingPoints_Red, HitObjects
    try:
        if file_select.get() == '':
            raise Exception(didnt_choose_file)
        
        if not os.path.isfile(file_select.get()):
            raise Exception(file_not_exist)
        
        basebpm = base_bpm.get()
        if basebpm == '':
            raise Exception(base_bpm_not_filled)
        else:
            if float(basebpm) >= 1000000:
                raise Exception(base_bpm_big)
            elif float(basebpm) >= 0 and float(basebpm) < 1:
                raise Exception(base_bpm_small)
            # elif float(bbasebpmpm) <= 0:
            #     raise Exception(base_bpm_should_be_positive)
                # bpm = str(60000 / float(basebpm))
        basebpm = float(basebpm)

        New_Green_adjust = []
        New_Red_adjust = []
        changed = []
        for line in TimingPoint_Red:
            cur_red = line.split(',')
            if float(cur_red[1]) < 0.06 or float(cur_red[1]) > 60000:
                continue
            else:
                cur_sv = basebpm / (60000 / float(cur_red[1]))
                if cur_sv > 10:
                    multi = 2 * (cur_sv // 10)
                    New_Red_adjust.append(','.join([str(cur_red[0])] + [str(float(cur_red[1]) / multi)] + cur_red[2:6] + ['1'] + (['0\n'] if int(cur_red[7]) in [0, 8] else ['1\n'])))
                    New_Green_adjust.append(','.join([str(cur_red[0])] + [str((-100 / cur_sv) * multi)] + cur_red[2:6] + ['0'] + (['0\n'] if int(cur_red[7]) in [0, 8] else ['1\n'])))
                    changed.append(f'{str(cur_red[0])}: {str(round(60000 / float(cur_red[1]), 4))} → {str(round(60000 / float(cur_red[1]) / multi, 4))}')
                elif cur_sv < 0.01:
                    multi = 2 * (0.01 // cur_sv)
                    New_Red_adjust.append(','.join([str(cur_red[0])] + [str(float(cur_red[1]) * multi)] + cur_red[2:6] + ['1'] + (['0\n'] if int(cur_red[7]) in [0, 8] else ['1\n'])))
                    New_Green_adjust.append(','.join([str(cur_red[0])] + [str((-100 / cur_sv) / multi)] + cur_red[2:6] + ['0'] + (['0\n'] if int(cur_red[7]) in [0, 8] else ['1\n'])))
                    changed.append(f'{str(cur_red[0])}: {str(round(60000 / float(cur_red[1], 4)))} → {str(round(60000 / float(cur_red[1]) * multi, 4))}')
                else:
                    New_Red_adjust.append(line)
                    New_Green_adjust.append(','.join([str(cur_red[0])] + [str(-100 / cur_sv)] + cur_red[2:6] + ['0'] + (['0\n'] if int(cur_red[7]) in [0, 8] else ['1\n'])))

        Combine_Adjust = sorted(New_Red_adjust + New_Green_adjust, key=lambda x: (int(x.split(',')[0]), -int(x.split(',')[6])))

        diff_name = f'{filename_info["Artist"]} - {filename_info["Title"]} ({filename_info["Creator"]}) [{filename_info["Version"]}].osu'
        diff_name_convert = f'{filename_info["Artist"]} - {filename_info["Title"]} ({filename_info["Creator"]}) [{filename_info["Version"]} (NB Convert)].osu'
        if ori.get() == 1:
            filename = f'{os.path.dirname(file_select.get())}/' + sanitize_filename(diff_name)
            New_Info = Info
        else:
            filename = f'{os.path.dirname(file_select.get())}/' + sanitize_filename(diff_name_convert)
            New_Info = []
            for line in Info:
                if line[0:8] == 'Version:':
                    New_Info.append(line[0:-1] + ' (NB Convert)\n')
                    continue
                New_Info.append(line)

        with open(filename, 'w', encoding='utf-8') as f:
            for line in New_Info:
                f.write(line)
            f.write('\n')
            f.write('[TimingPoints]\n')
            for line in Combine_Adjust:
                f.write(line)
            f.write('\n')
            f.write('[HitObjects]\n')
            for line in HitObjects:
                f.write(line)
            f.close()

        if changed == []:
            log_add_msg(adjust_done)
        else:
            log_add_msg(adjust_done + '\n\n' + red_changed + '\n' + '\n'.join(changed))
        init(if_all=True)
        read_file()
    except Exception as e:
        log_add_msg(e)

