def combine_file():
    global Combine_TimingPoints, Combine_HitObjects, New_TimingPoints_Red, New_TimingPoints_Green, TimingPoint_Red, TimingPoint_Green, New_HitObjects, Info
    # for i in New_TimingPoints_Red:
    #     print(i)
    # for i in New_TimingPoints_Green:
    #     print(i)

    Combine_Red = TimingPoint_Red.copy()
    for new in New_TimingPoints_Red:
        found = False
        for i, line in enumerate(Combine_Red):
            if int(line.split(',')[0]) == int(new.split(',')[0]):
                Combine_Red[i] = new
                found = True
                break
        if not found:
            Combine_Red.append(new)
                
    Combine_Green = TimingPoint_Green.copy()
    for new in New_TimingPoints_Green:
        found = False
        for i, line in enumerate(Combine_Green):
            if int(line.split(',')[0]) == int(new.split(',')[0]):
                Combine_Green[i] = new
                found = True
                break
        if not found:
            Combine_Green.append(new)
    
    Combine_TimingPoints = sorted(Combine_Red + Combine_Green, key=lambda x: (int(x.split(',')[0]), -int(x.split(',')[6])))

    Combine_HitObjects = HitObjects.copy()
    for new in New_HitObjects:
        found = False
        for i, line in enumerate(Combine_HitObjects):
            if int(line.split(',')[2]) == int(new.split(',')[2]):
                Combine_HitObjects[i] = new
                found = True
                break
        if not found:
            Combine_HitObjects.append(new)

    Combine_HitObjects = sorted(Combine_HitObjects, key=lambda x: int(x.split(',')[2]))

    diff_name = f'{filename_info["Artist"]} - {filename_info["Title"]} ({filename_info["Creator"]}) [{filename_info["Version"]}].osu'
